import logger from '@utils/logger'; // Alias import

/**
 * Loads and validates secrets from environment variables.
 */
export const loadSecrets = (): void => {
  const requiredSecrets = ['JWT_SECRET', 'API_KEY']; // Example required secrets
  const missingSecrets = requiredSecrets.filter(secretName => !process.env[secretName]);

  if (missingSecrets.length > 0) {
    logger.error('Missing secrets', { missing: missingSecrets });
    process.exit(1);
  }

  logger.info('Secrets loaded successfully');
};

// Call loadSecrets() at app startup
loadSecrets();

